query:
CREATE TABLE IF NOT EXISTS discovery_drafts (
  id INT AUTO_INCREMENT PRIMARY KEY,
  intake_id INTEGER NOT NULL REFERENCES intakes(id) ON DELETE CASCADE,
  type VARCHAR(50) NOT NULL,
  title VARCHAR(255),
  content JSON,
  created_by_id INTEGER,
  created_by_name VARCHAR(255),
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL,
  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL ON UPDATE CURRENT_TIMESTAMP
);

CREATE INDEX IF NOT EXISTS idx_discovery_drafts_intake_id ON discovery_drafts(intake_id);
CREATE INDEX IF NOT EXISTS idx_discovery_drafts_type ON discovery_drafts(type);

